import{_ as e,o as t,c as s,a0 as n}from"./chunks/framework.Dx25mwie.js";const u=JSON.parse('{"title":"http-gen","description":"","frontmatter":{"head":[]},"headers":[],"relativePath":"docs/2.guides/08-http-gen.md","filePath":"docs/2.guides/08-http-gen.md"}'),d={name:"docs/2.guides/08-http-gen.md"};function i(l,a,o,p,c,r){return t(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="http-gen" tabindex="-1">http-gen <a class="header-anchor" href="#http-gen" aria-label="Permalink to &quot;http-gen&quot;">​</a></h1><p>http-gen 是一个基于 IDL 定义生成 Go HTTP 服务端和客户端代码的工具。</p><h2 id="项目结构与依赖" tabindex="-1">项目结构与依赖 <a class="header-anchor" href="#项目结构与依赖" aria-label="Permalink to &quot;项目结构与依赖&quot;">​</a></h2><p>典型的 http-gen 项目结构：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>project/</span></span>
<span class="line"><span>├── meta.json        # 元信息（包名、输出路径等）</span></span>
<span class="line"><span>├── api/             # IDL 文件目录</span></span>
<span class="line"><span>│   ├── user.idl</span></span>
<span class="line"><span>│   └── order.idl</span></span>
<span class="line"><span>└── ...</span></span></code></pre></div><ul><li>支持 <code>import</code> 机制引入外部 IDL 文件</li><li>多个 IDL 共享同一个命名空间</li></ul><h2 id="idl-语法与语义" tabindex="-1">IDL 语法与语义 <a class="header-anchor" href="#idl-语法与语义" aria-label="Permalink to &quot;IDL 语法与语义&quot;">​</a></h2><h3 id="注释" tabindex="-1">注释 <a class="header-anchor" href="#注释" aria-label="Permalink to &quot;注释&quot;">​</a></h3><div class="language-idl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">idl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 单行注释</span></span>
<span class="line"><span></span></span>
<span class="line"><span>/*</span></span>
<span class="line"><span>   多行注释</span></span>
<span class="line"><span>*/</span></span></code></pre></div><h3 id="关键字" tabindex="-1">关键字 <a class="header-anchor" href="#关键字" aria-label="Permalink to &quot;关键字&quot;">​</a></h3><table tabindex="0"><thead><tr><th>关键字</th><th>说明</th></tr></thead><tbody><tr><td><code>extends</code></td><td>扩展枚举</td></tr><tr><td><code>const</code></td><td>常量定义</td></tr><tr><td><code>enum</code></td><td>枚举定义</td></tr><tr><td><code>type</code></td><td>类型定义</td></tr><tr><td><code>oneof</code></td><td>联合类型</td></tr><tr><td><code>rpc</code></td><td>RPC 方法定义</td></tr><tr><td><code>sse</code></td><td>流式响应（Server-Sent Events）</td></tr><tr><td><code>true</code>/<code>false</code></td><td>布尔值</td></tr><tr><td><code>optional</code></td><td>可选字段</td></tr><tr><td><code>required</code></td><td>必填字段</td></tr></tbody></table><h3 id="基础类型" tabindex="-1">基础类型 <a class="header-anchor" href="#基础类型" aria-label="Permalink to &quot;基础类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>bool</code></td><td>布尔</td></tr><tr><td><code>int</code></td><td>有符号整数（不内置 uint，可自定义）</td></tr><tr><td><code>float</code></td><td>浮点数</td></tr><tr><td><code>string</code></td><td>字符串</td></tr><tr><td><code>bytes</code></td><td>字节数组</td></tr><tr><td><code>list</code></td><td>列表切片</td></tr><tr><td><code>map</code></td><td>映射字典</td></tr></tbody></table><p>支持多层嵌套。</p><h3 id="常量" tabindex="-1">常量 <a class="header-anchor" href="#常量" aria-label="Permalink to &quot;常量&quot;">​</a></h3><div class="language-idl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">idl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>const MAX_USERS = 1000;</span></span></code></pre></div><h3 id="注解" tabindex="-1">注解 <a class="header-anchor" href="#注解" aria-label="Permalink to &quot;注解&quot;">​</a></h3><div class="language-idl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">idl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@route(&quot;/api/users&quot;)      // 单行注解</span></span>
<span class="line"><span>@method(&quot;POST&quot;)</span></span></code></pre></div><p>语法：<code>@key(=value)?</code>，value 省略表示 <code>true</code> 布尔语义。</p><h3 id="枚举" tabindex="-1">枚举 <a class="header-anchor" href="#枚举" aria-label="Permalink to &quot;枚举&quot;">​</a></h3><div class="language-idl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">idl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>enum ErrorCode {</span></span>
<span class="line"><span>    OK = 0 @errmsg(&quot;success&quot;)</span></span>
<span class="line"><span>    NOT_FOUND = 1 @errmsg(&quot;not found&quot;)</span></span>
<span class="line"><span>}</span></span></code></pre></div><ul><li>支持 <code>errmsg</code> 注解存储错误信息</li><li>支持 <code>enum_as_string</code> 选项生成字符串枚举</li><li>支持 <code>extends</code> 扩展合并其他枚举</li></ul><h3 id="类型-结构体" tabindex="-1">类型（结构体） <a class="header-anchor" href="#类型-结构体" aria-label="Permalink to &quot;类型（结构体）&quot;">​</a></h3><div class="language-idl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">idl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>type User {</span></span>
<span class="line"><span>    required int64 id;</span></span>
<span class="line"><span>    required string username;</span></span>
<span class="line"><span>    optional string avatar;</span></span>
<span class="line"><span>    @pattern(&quot;^[a-z]+$&quot;) string name;</span></span>
<span class="line"><span>}</span></span></code></pre></div><ul><li>支持普通结构体、泛型结构体</li><li>支持嵌套字段、嵌入类型（字段合并）</li><li>支持联合类型 <code>oneof</code>（枚举 + 结构体）</li><li>支持字段校验： <ul><li>内置校验函数</li><li>自定义校验函数</li><li>运算符表达式，<code>$</code> 表示当前字段值</li></ul></li></ul><h2 id="接口定义" tabindex="-1">接口定义 <a class="header-anchor" href="#接口定义" aria-label="Permalink to &quot;接口定义&quot;">​</a></h2><div class="language-idl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">idl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>rpc CreateUser(CreateUserRequest) returns (CreateUserResponse) @method(&quot;POST&quot;) @path(&quot;/api/users&quot;);</span></span></code></pre></div><ul><li>支持 <code>rpc</code> 普通方法</li><li>支持 <code>sse</code> 流式响应方法</li><li>接口注解支持 <code>method</code>、<code>path</code>、<code>contentType</code>、<code>timeout</code> 等</li><li>Restful 路径参数支持 <code>:name</code> 或 <code>{name}</code> 语法，仅支持 <code>int</code>/<code>string</code> 类型</li></ul><h2 id="代码生成器" tabindex="-1">代码生成器 <a class="header-anchor" href="#代码生成器" aria-label="Permalink to &quot;代码生成器&quot;">​</a></h2><ul><li>生成 Go 服务端骨架代码</li><li>生成 Go 客户端调用代码</li><li>流式解析优化：支持 <code>required</code> 校验，流式 JSON/form 解析，性能更好</li></ul><p>使用方式：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> github.com/go-spring/gs-http-gen/cmd/gs-http-gen</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> meta.json</span></span></code></pre></div>`,32)])])}const g=e(d,[["render",i]]);expo